   431→	lg := a.s.Logger()
   432→	trace := traceutil.Get(ctx)
   433→	if trace.IsEmpty() {
   434→		trace = traceutil.New("transaction", a.s.Logger())
   435→		ctx = context.WithValue(ctx, traceutil.TraceKey, trace)
   436→	}
   437→	isWrite := !isTxnReadonly(rt)
